# NAT Gateway per AZ — eliminates NAT as SPOF
resource "aws_eip" "nat_a" { domain = "vpc" }
resource "aws_eip" "nat_b" { domain = "vpc" }
resource "aws_eip" "nat_c" { domain = "vpc" }

resource "aws_nat_gateway" "a" {
  allocation_id = aws_eip.nat_a.id
  subnet_id     = aws_subnet.public_a.id
}
resource "aws_nat_gateway" "b" {
  allocation_id = aws_eip.nat_b.id
  subnet_id     = aws_subnet.public_b.id
}
resource "aws_nat_gateway" "c" {
  allocation_id = aws_eip.nat_c.id
  subnet_id     = aws_subnet.public_c.id
}

# Each private subnet routes to its AZ's NAT GW
resource "aws_route" "private_a_nat" {
  route_table_id         = aws_route_table.private_a.id
  destination_cidr_block = "0.0.0.0/0"
  nat_gateway_id         = aws_nat_gateway.a.id
}

import boto3
import time
import random

def call_with_retry(fn, max_attempts=3, base_delay=0.5):
    """Exponential backoff with jitter for AWS SDK calls."""
    for attempt in range(max_attempts):
        try:
            return fn()
        except Exception as e:
            if attempt == max_attempts - 1:
                raise
            delay = base_delay * (2 ** attempt) + random.uniform(0, 0.1)
            time.sleep(delay)

# boto3 has built-in retry configuration
from botocore.config import Config

config = Config(
    retries={
        'max_attempts': 5,
        'mode': 'adaptive'  # Adaptive mode: backs off on throttling signals
    }
)
s3 = boto3.client('s3', config=config)

# AWS FIS experiment: terminate 1/3 of EC2 instances in ASG
aws fis create-experiment-template \
  --description 'Test ASG recovery from instance failure' \
  --actions '{
    "terminateInstances": {
      "actionId": "aws:ec2:terminate-instances",
      "parameters": { "percentage": "33" },
      "targets": { "Instances": "webInstances" }
    }
  }' \
  --targets '{
    "webInstances": {
      "resourceType": "aws:ec2:instance",
      "resourceTags": { "aws:autoscaling:groupName": "web-asg" },
      "selectionMode": "PERCENT(33)"
    }
  }' \
  --role-arn arn:aws:iam::123456789012:role/FISRole

# Start the experiment
aws fis start-experiment --experiment-template-id EXT123

# Route 53 failover routing: primary us-east-1, failover us-west-2
resource "aws_route53_health_check" "primary" {
  fqdn              = "api.us-east-1.example.com"
  port              = 443
  type              = "HTTPS"
  resource_path     = "/health"
  failure_threshold = 2
  request_interval  = 10
}

resource "aws_route53_record" "primary" {
  zone_id = var.hosted_zone_id
  name    = "api.example.com"
  type    = "A"
  set_identifier = "primary"
  failover_routing_policy { type = "PRIMARY" }
  health_check_id = aws_route53_health_check.primary.id
  alias {
    name                   = aws_lb.primary.dns_name
    zone_id                = aws_lb.primary.zone_id
    evaluate_target_health = true
  }
}

resource "aws_route53_record" "failover" {
  zone_id        = var.hosted_zone_id
  name           = "api.example.com"
  type           = "A"
  set_identifier = "failover"
  failover_routing_policy { type = "SECONDARY" }
  alias {
    name                   = aws_lb.secondary.dns_name
    zone_id                = aws_lb.secondary.zone_id
    evaluate_target_health = true
  }
}
